from kafka import KafkaConsumer, TopicPartition
import json

def deserialize_object(serialized_data):
    # Implement your deserialization logic here
    return json.loads(serialized_data)

def process_transaction(transaction):
    # Implement your business logic for transaction processing here
    print(f"Processing transaction: {transaction}")

def message_handler(message):
    try:
        transaction = deserialize_object(message.value)
        process_transaction(transaction)
    except Exception as e:
        print(f"Error processing message: {e}")

# Configure Kafka consumer
consumer = KafkaConsumer(
    bootstrap_servers='localhost:9092',
    group_id='transaction-group',
    auto_offset_reset='earliest',
    enable_auto_commit=True,
    auto_commit_interval_ms=1000,
    key_deserializer=lambda x: x.decode('utf-8'),
    value_deserializer=lambda x: x  # Raw bytes, to be deserialized later
)

# Subscribe to the topics
consumer.subscribe(['financial_transactions'])

# Consume messages dynamically
for message in consumer:
    message_handler(message)